// 조회 후처리
scwin.sbm_retrieve_submitdone = async function () {
  ds_crosstab.removeAll(); // 기존 데이터 지움

  var rowCount = ds_fix_work_list.getRowCount();
  gr_work_pl.setColumnVisible("column68", true);
  for (var i = 1; i <= 10; i++) {
    gr_work_pl.setColumnVisible("bilgAmt" + i, false);
  }
  if (rowCount == 0) {
    total.setValue(0); // 총건수
    await $c.gus.cfAlertMsg($p, "조회된 데이터가 없습니다.");
    return;
  }
  var options = {};
  options.sortIndex = "vehclNo outAcctCd";
  options.sortOrder = "1 1";
  ds_fix_work_list.multisort(options);
  var oringJSON = ds_fix_work_list.getAllJSON();
  var colData = [];
  var crossRJson = {};
  var allJson = [];
  oringJSON.forEach(function (rowJson) {
    //컬럼 생성
    if (!colData.includes(rowJson.outAcctCd)) {
      colData.push(rowJson.outAcctCd);
    }
    if (colData.length >= 11) return; //colData가 11개 이상이면 컬럼수 추가 해줘야함.

    var keyData = rowJson.vehclNo + "_" + rowJson.acctDeptNm + "_" + rowJson.eqKndCd + "_" + rowJson.prdyr;
    if (!crossRJson[keyData]) {
      crossRJson[keyData] = rowJson;
    }
    var outAcctCdidx = colData.indexOf(rowJson.outAcctCd);
    if (outAcctCdidx > -1) {
      crossRJson[keyData]["bilgAmt" + (outAcctCdidx + 1)] = rowJson.bilgAmt;
    }
  });
  for (key in crossRJson) {
    allJson.push(crossRJson[key]);
  }
  ds_crosstab.setJSON(allJson);
  gr_work_pl.setColumnVisible("column68", false);
  for (var i = 1; i <= colData.length; i++) {
    gr_work_pl.setHeaderValue("column" + i, colData[i - 1]);
    gr_work_pl.setColumnVisible("bilgAmt" + i, true);
  }
  total.setValue(ds_crosstab.getRowCount()); // 총건수
};

// 정비작업장 콤보박스 조회 후처리
scwin.sbm_lc_wrkPlCd_submitdone = function () {
  //for=ds_lux_wrkPlCd event=OnLoadCompleted(rowCnt)
  lc_wrkPlCd.setSelectedIndex(0);
  if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
    lc_wrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); // 정비작업장코드
  }
};

// 대표정비작업장 콤보박스 조회 후처리
scwin.sbm_combo_submitdone = function () {
  //for=co_ds_combo event=OnLoadCompleted(rowCnt)
  ds_combo.sort("code", 0); //tobe추가 : asis와 동일하게 하기 위해 추가.

  lc_repWrkPlCd.setSelectedIndex(0);
  if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
    lc_repWrkPlCd.setValue(scwin.userInfo.fixWrkPlCd);
  }
  scwin.lc_repWrkPlCd_onviewchange(); // 이벤트 발생안해서 강제 호출
};

// 합계 컬럼 푸터 포멧
scwin.zeroToEmpty = function (data) {
  var value = "";
  if (data != 0) {
    value = $c.num.formatNumber($p, data);
  }
  return value;
};
